def count_new_items_recursive(path: str, max_date) -> int:

    # ✅ auto-convert if string
    if isinstance(max_date, str):
        max_date = datetime.strptime(
            max_date, "%Y-%m-%dT%H:%M:%S.%f+0000"
        )

    count = 0

    try:
        items = mssparkutils.fs.ls(path)

        for item in items:
            item_time = datetime.fromtimestamp(item.modifyTime / 1000)

            if item.isDir:
                count += count_new_items_recursive(item.path, max_date)
            else:
                if max_date is None or item_time > max_date:
                    count += 1

    except Exception as e:
        print(f"Error reading path {path}: {e}")

    return count
